5	const neighborsOf = ([x, y]: Cell): Cell[] => {
6	  const neighbors: Cell[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      neighbors.push([x + dx, y + dy]);
11	    }
12	  }
13	  return neighbors;
14	};
